module top_module(
    input obf_A,
    input enable,
    input sleep,
    output reg X
);always @(obf_A, enable, sleep) begin
    if (sleep) begin
        // If sleep is high, hold the output at the last value of obf_A
        X <= X;
    end else if (enable) begin
        // If enable is high, pass the input signal to the output
        X <= obf_A;
    end else begin
        // If enable is low, hold the output at the last value of obf_A
        X <= X;
    end
end

endmodule
